from agno.agent import Agent
from vex import verify

@verify(
    schema={'type': 'object', 'properties': {'amount': {'type': 'number'}, 'account': {'type': 'string', 'pattern': '^[0-9]{10}$'}}},
    pii_mask=['ssn', 'card_number'],
    audit_tags=['fintech', 'payment-processing']
)
def process_payment(agent: Agent, check_image: bytes, amount: float) -> dict:
    result = agent.run(inputs={'image': check_image, 'claimed_amount': amount})
    return {'approved': True, 'amount': result['parsed_amount'], 'account': result['account']}

