from agno.memory import Memory
from vex import verify

class AMLAgent(Agent):
    memory = Memory()

    @verify(
        memory_check=True,
        hallucination_threshold=0.1,
        required_evidence='transaction_history',
        tags=['aml', 'kyc']
    )
    def assess_customer_risk(self, customer_id: str) -> dict:
        # Agent recalls prior interactions
        risk_score = self.memory.get(f'risk_{customer_id}')
        return {
            'risk_score': risk_score,
            'evidence': self.memory.evidence_chain(customer_id)
        }

from agno import Team
from vex import verify

risk_team = Team(agents=[risk_agent, fraud_agent])
approval_team = Team(agents=[credit_agent, compliance_agent])

@verify(
    cross_check=True,
    consistency_threshold=0.9,
    schema={'risk_score': {'type': 'number', 'minimum': 0, 'maximum': 1}},
    tags=['credit-decision', 'sec-regulated']
)
def reconcile_credit_decision(customer_data: dict) -> dict:
    risk_results = risk_team.run(customer_data)
    approval_results = approval_team.run(customer_data)

    final_decision = {
        'approved': risk_results['risk_score'] < 0.3 and approval_results['approved'],
        'explanation': 'Risk and approval teams aligned',
        'audit_evidence': {'risk': risk_results, 'approval': approval_results}
    }
    return final_decision
